import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        // Treat both whitespace and the literal string "\\n" as delimiters
        sc.useDelimiter("\\s+|\\\\n");
        StringBuilder output = new StringBuilder();
        int T = sc.nextInt();
        for (int tc = 0; tc < T; tc++) {
            int N = sc.nextInt();
            int index = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            // Build result with insertion of 99 at position 'index'
            for (int i = 0; i <= N; i++) {
                if (i == index) {
                    output.append(99).append(' ');
                }
                if (i < N) {
                    output.append(arr[i]).append(' ');
                }
            }
            // Remove trailing space for this test case
            if (output.length() > 0 && output.charAt(output.length() - 1) == ' ') {
                output.setLength(output.length() - 1);
            }
            output.append('\n');
        }
        System.out.print(output.toString());
    }
}

